async (params, browser) => {
  // Open business page
  await browser.open(`${params.business_url}`)

  // Wait for page
  await browser.waitForSelector('h1, [class*=\'businessName\']', 15000)

  await browser.wait(2000)

  // Scroll to menu section
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(1500)

  // Extract menu
  const menu_data = await browser.evaluate(`const menuSections = []; const sectionEls = document.querySelectorAll('[class*="menu-section"], [class*="menu_section"], section[class*="menu"]'); if (sectionEls.length > 0) { sectionEls.forEach(function(section) { const titleEl = section.querySelector('h2, h3, [class*="section-header"]'); const items = []; section.querySelectorAll('[class*="menu-item"], [class*="menu_item"], li').forEach(function(item) { const nameEl = item.querySelector('[class*="item-name"], h4, [class*="name"]'); const priceEl = item.querySelector('[class*="price"], [class*="cost"]'); const descEl = item.querySelector('[class*="description"], p'); if (nameEl) { items.push({ name: nameEl.textContent.trim(), price: priceEl ? priceEl.textContent.trim() : '', description: descEl ? descEl.textContent.trim().substring(0, 200) : '' }); } }); menuSections.push({ section: titleEl ? titleEl.textContent.trim() : '', item_count: items.length, items: items.slice(0, 20) }); }); } else { const popularItems = []; document.querySelectorAll('[class*="dish"], [class*="popular-menu"] [class*="item"]').forEach(function(el) { const nameEl = el.querySelector('[class*="name"], h4, a'); const priceEl = el.querySelector('[class*="price"]'); const imgEl = el.querySelector('img'); popularItems.push({ name: nameEl ? nameEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '', image: imgEl ? imgEl.getAttribute('src') : '' }); }); if (popularItems.length > 0) { menuSections.push({ section: 'Popular Dishes', item_count: popularItems.length, items: popularItems }); } } const nameEl = document.querySelector('h1'); return { business_name: nameEl ? nameEl.textContent.trim() : '', section_count: menuSections.length, menu: menuSections, url: window.location.href }`)

  return menu_data
}
